import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"The Rundown AI — 2026-05-05","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-05","date":"2026-05-05T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-05-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-05-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-05/2026-05-05-the-rundown-ai.md"};function i(s,e,p,m,h,l){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🗞️-the-rundown-ai-—-2026-05-05" tabindex="-1">🗞️ The Rundown AI — 2026-05-05 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-05" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-05&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="ai-data-centers-head-for-the-ocean" tabindex="-1"><a href="https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">AI data centers head for the ocean</a> <a class="header-anchor" href="#ai-data-centers-head-for-the-ocean" aria-label="Permalink to &quot;[AI data centers head for the ocean](https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-05</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. AI&#39;s land grab is running into walls — literal ones, in the form of an angry public fed up with data center constructions in their cities.</p><p>Oregon-based startup Panthalassa is taking things offshore instead, with Peter Thiel leading a new $140M round for floating structures that turn ocean energy into the compute AI companies are all scrambling for more of.</p><p>In today’s AI rundown:</p><p>Thiel-backed startup brings AI data centers to sea</p><p>Anthropic co-founder forecasts AI’s self-building era</p><p>How to replace Siri with a free local model</p><p>OAI, Anthropic launching rival private equity ventures</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>PETER THIEL &amp; PANTHALASSA</p><p>🌊 <a href="https://www.businesswire.com/news/home/20260504552400/en/Panthalassa-Raises-%24140-Million-to-Power-AI-at-Sea?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Thiel-backed startup brings AI data centers to sea</a></p><p>Image source: Panthalassa</p><p>The Rundown: PayPal and Palantir founder Peter Thiel just <a href="https://www.businesswire.com/news/home/20260504552400/en/Panthalassa-Raises-%24140-Million-to-Power-AI-at-Sea?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">led</a> a $140M Series B for Panthalassa, an Oregon-based startup that builds autonomous floating compute structures powered by ocean waves — reportedly valuing the company at nearly $1B.</p><p>The details:</p><p>Each 85-meter steel node bobs in open ocean, converting wave motion into electricity for onboard AI chips, all cooled naturally by seawater.</p><p>Once deployed, the nodes can steer themselves to remote waters using only their hull shape (no engines) and beam AI results back via SpaceX’s Starlink.</p><p>The raise will finish a pilot factory near Portland and deploy the first wave-powered compute nodes in the Pacific Ocean, with commercial rollout in 2027.</p><p>Thiel <a href="https://www.ft.com/content/711ce313-16fb-4a12-b6be-fbed547c8a39?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">told</a> the Financial Times that “extraterrestrial solutions (to compute) are no longer science fiction” and that “Panthalassa has opened the ocean frontier.”</p><p>Why it matters: AI data centers have been one of the more controversial AI talking points for the general public, and the hostility towards their construction is growing fast. While both Elon Musk and Google have pushed space-based options, those are still far from reality, making the ocean an interesting and more realistic alternative.</p><p>TOGETHER WITH YOU.COM</p><p>⏰ <a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer">API latency is only part of the story</a></p><p><a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Most teams pick an API by checking a benchmark table and calling it done—a shortcut that could miss what really matters in production. This guide from <a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer">You.com</a> explains why raw latency is a misleading signal and what to measure instead.</p><p>What you&#39;ll learn:</p><p>Why p50 latency hides the failures your users actually experience</p><p>The &quot;time-to-useful-result&quot; framework that captures what benchmarks leave out</p><p>Four hidden cost drivers that show up in your logs, not vendor tables</p><p>How to evaluate APIs at your actual concurrency levels, not the demo conditions</p><p>Learn what to measure instead. <a href="https://you.com/resources/why-api-latency-alone-is-a-misleading-metric-download?utm_campaign=28104480-The%20Rundown%20Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_5.5.26&amp;utm_content=rundown_primary_5.5.26" target="_blank" rel="noreferrer">Download the guide</a>.</p><p>ANTHROPIC</p><p>📝 <a href="https://importai.substack.com/p/import-ai-455-automating-ai-research?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Anthropic co-founder forecasts AI’s self-building era</a></p><p>Image source: Jack Clark (@JackclarkSF on X) / The Rundown</p><p>The Rundown: Anthropic co-founder Jack Clark <a href="https://importai.substack.com/p/import-ai-455-automating-ai-research?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">published</a> a new blog post on self-improving AI, putting 60%+ odds on AI systems training their own successors before 2029, citing public data showing AI is already handling a range of core R&amp;D tasks.</p><p>The details:</p><p>Clark built the case on public papers and benchmark data, charting AI going from near-zero to 100% across core development tasks in under 3 years.</p><p>METR <a href="https://metr.org/time-horizons/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">data</a> shows AI’s independent work capability went from 30-second tasks in 2022 to 12 hours in 2026, with 100-hour runs projected by year-end.</p><p>Clark also pointed to the SWE-Bench benchmark (real GitHub coding), moving from Claude 2 at 2% to Mythos Preview at 93.9% in under three years.</p><p>OpenAI is also <a href="https://x.com/sama/status/1983584366547829073?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">targeting</a> an automated research intern by Sept. 2026, while startups like Recursive Superintelligence share similar self-improvement goals.</p><p>Why it matters: Self-improving AI systems feel like the inflection point that really makes model development go exponential, and “by the end of 2028” is not that far away. AI is already moving at a speed that is hard for most to process — but once it can reliably build and train itself, all bets are off for how fast things can truly move.</p><p>AI TRAINING</p><p>📲 <a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">How to replace Siri with a free local model</a></p><p><a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to download a free AI model to your iPhone and bind it to your phone&#39;s action button like Siri. The model is installed locally, so you will be able to use it without the internet or sending out your private data.</p><p>Step-by-step:</p><p>Download <a href="https://apps.apple.com/us/app/locally-ai-local-ai-chat/id6741426692?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Locally AI</a> from the App Store, choose your model. You can start with Google’s new, open-source Gemma model, which typically works great</p><p>Download the AI and keep the app open. Now, open settings, search for Action Button, swipe to the Shortcut option, search Locally AI, and choose Voice Mode</p><p>Press the Action Button on your iPhone and wait for the chime. The app will ask you to download a speech-to-text model the first time. Download it</p><p>Now try asking the model a question. We found they are best for explaining concepts, translation tasks, and math</p><p>Pro tip: Download a bigger model and run the same prompt through it. Compare speed, storage size, and answer quality to get the perfect AI for your iPhone.</p><p>AI &amp; THE ENTERPRISE</p><p>💰 <a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">OAI, Anthropic launching rival private equity ventures</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: Anthropic <a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">announced</a> the formation of a new Claude services company with Blackstone, Hellman &amp; Friedman, and Goldman Sachs, with OpenAI also reportedly <a href="https://finance.yahoo.com/sectors/technology/articles/openai-finalizes-10-billion-joint-123100557.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">raising</a> for its own PE-backed ‘Deployment Company’ the same day.</p><p>The details:</p><p>The $1.5B Anthropic venture will focus on mid-sized companies, pairing its Applied AI engineers with teams building custom Claude workflows.</p><p>OAI&#39;s &quot;Deployment Company&quot; will reportedly bring in $4B from 19 investors at a $10B valuation, including TPG, Brookfield, Bain, and SoftBank.</p><p>Both models would give the frontier AI labs direct paths into portfolio companies that often lack the in-house talent to deploy AI systems alone.</p><p>Why it matters: The barriers for companies aren’t the models anymore, but actually getting it installed and integrated into messy, large-scale businesses. These paths look more like frontier labs creating their own AI-native consulting firms, with a wealth of private equity portfolio companies ready to get in on the action.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🗣️ <a href="https://www.unwrap.ai/product-product-operations-ai-product?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Unwrap Customer Intelligence</a> - Get AI-driven insights from your unstructured customer feedback to build your product roadmap*</p><p>🚀 <a href="https://www.rundown.ai/tools/grok-4-3?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Grok 4.3</a> - xAI’s AI with strong cost efficiency, domain-specific performance</p><p>🤖 <a href="https://www.rundown.ai/tools/cofounder-2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Cofounder 2</a> - General Intelligence&#39;s new agent orchestrator for businesses</p><p>🦮 <a href="https://www.rundown.ai/tools/codex-pets?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Codex Pets</a> - OpenAI&#39;s animated companions for tracking Codex work</p><p>*Sponsored Listing</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>A new filing in the Elon Musk vs. OpenAI case <a href="https://www.cnbc.com/2026/05/04/musk-altman-open-ai-settlement-trial-brockman.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">showed</a> that Musk reached out to OAI President Greg Brockman about a potential settlement days before the trial.</p><p>The New York Times <a href="https://www.nytimes.com/2026/05/04/technology/trump-ai-models.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">reported</a> that the White House is seeking to create a formal review and oversight process prior to companies publicly deploying AI models.</p><p>Sierra <a href="https://sierra.ai/blog/better-customer-experiences-built-on-sierra?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">raised</a> $950M at a $15B valuation, with the platform saying it now serves over 40% of the Fortune 50 companies for AI-driven customer experiences.</p><p>Roomba creator and former iRobot CEO Colin Angle <a href="https://apnews.com/article/ai-pet-robot-familiar-machines-irobot-roomba-da873ddff1ebcc95f793852b8e53d2d2?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">introduced</a> the Familiar, a bulldog-sized AI pet robot targeting retirees who&#39;ve aged out of pet ownership.</p><p>Anthropic is reportedly in talks to <a href="https://www.theinformation.com/articles/anthropic-talks-buy-ai-chips-u-k-startup?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">purchase</a> chips from Fractile, a three-year-old London startup focused on more efficient chips for running AI models.</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Adam M. in Berlin, Germany:</p><p>My best friend Eric was in a horse riding accident, which has left him partially paralyzed from the neck down. His medical insurance would only cover some of it. He was in a remote place in South Africa, so he needed to be flown by helicopter to the nearest hospital and then undergo multiple surgeries.</p><p>We used AI to help us set up the GoFundMe page and create social media posts for him, and to manage his ongoing recovery. Given that he can&#39;t really use his hands, he&#39;s able to use his phone now with AI to give updates and share about his journey with the world so that we can get the message out there to help him recover.</p><p>We&#39;re also using it to stay up to date with GoFundMe and their documentation and what they need to prove that he&#39;s a real person and that it isn&#39;t a scam. Whenever they send requests, we can paste them into Claude and get a properly formatted answer back so they can speed up the approval process, release their funds, and make sure they&#39;re happy.</p><p>It also helped us estimate what we should do in terms of a goal. We&#39;ve set the goal at half a million euros, and we are well on the way.&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/ai-shows-its-skills-in-the-emergency-room?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">AI shows its skills in the emergency room</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/spacex-rocket-to-crash-into-the-moon?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">SpaceX is about to crash into the Moon</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/how-to-replace-siri-with-a-free-local-model?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=ai-data-centers-head-for-the-ocean" target="_blank" rel="noreferrer">How to replace Siri with a free local model</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',95)])])}const c=a(o,[["render",i]]);export{d as __pageData,c as default};
